const price = +$json.price;
const rent = +$json.monthly_rent;
const expenses = +$json.annual_expenses;

const annualRent = rent * 12;
const profit = annualRent - expenses;

const rentalYield = (annualRent / price) * 100;
const roi = (profit / price) * 100;

return {
  json: {
    ...$json,
    annual_rent: annualRent,
    profit: profit,
    rental_yield: Number(rentalYield.toFixed(2)),
    roi: Number(roi.toFixed(2))
  }
};

