const current = $items("Calculate ROI & Yield")[0].json;
const currentPrice = String(current.price).trim();

// get ALL rows from history node
const history = $items("Check existing details");

// check duplicate
const isDuplicate = history.some(item => {
  return String(item.json.Price).trim() === currentPrice;
});

return [{
  json: {
    ...current,
    is_duplicate: isDuplicate
  }
}];

const aiData = $json;
const original = $items("Calculate ROI & Yield")[0].json;

return [{
  json: {
    ...original,
    ...aiData
  }
}];
